import{_ as a,o as e,c as r,ag as i}from"./chunks/framework.DEs8X8sU.js";const p=JSON.parse('{"title":"シフト管理","description":"","frontmatter":{"title":"シフト管理"},"headers":[],"relativePath":"tenant/12-shift.md","filePath":"tenant/12-shift.md"}'),d={name:"tenant/12-shift.md"};function l(o,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="_12-シフト管理" tabindex="-1">12. シフト管理 <a class="header-anchor" href="#_12-シフト管理" aria-label="Permalink to &quot;12. シフト管理&quot;">​</a></h1><p>シフト管理では、希望シフト、勤務表、出勤・退勤、ヘルプ要請、人件費の確認を行います。</p><h2 id="シフト作成の流れ" tabindex="-1">シフト作成の流れ <a class="header-anchor" href="#シフト作成の流れ" aria-label="Permalink to &quot;シフト作成の流れ&quot;">​</a></h2><ol><li>スタッフが希望シフトを提出します。</li><li>マネージャーが希望を確認します。</li><li>必要人数、役割、休憩時間を調整します。</li><li>シフトを確定してスタッフに共有します。</li><li>営業後に実績と差分を確認します。</li></ol><h2 id="勤怠打刻" tabindex="-1">勤怠打刻 <a class="header-anchor" href="#勤怠打刻" aria-label="Permalink to &quot;勤怠打刻&quot;">​</a></h2><p>スタッフは出勤時に出勤、退勤時に退勤を打刻します。GPS確認を利用している店舗では、店舗付近での打刻が必要です。</p><h2 id="ヘルプ要請" tabindex="-1">ヘルプ要請 <a class="header-anchor" href="#ヘルプ要請" aria-label="Permalink to &quot;ヘルプ要請&quot;">​</a></h2><p>人員が不足する場合、他店舗へヘルプを依頼できます。依頼内容、日時、役割、必要人数を明確にしてください。</p><h2 id="人件費確認" tabindex="-1">人件費確認 <a class="header-anchor" href="#人件費確認" aria-label="Permalink to &quot;人件費確認&quot;">​</a></h2><p>確定シフトと勤怠実績をもとに、人件費の目安を確認できます。給与計算の最終確定は、店舗または本部の運用ルールに従ってください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>打刻できない</td><td>ログイン中のアカウント、位置情報許可、店舗付近かを確認してください。</td></tr><tr><td>希望シフトが見えない</td><td>提出期間、対象スタッフ、表示週を確認してください。</td></tr><tr><td>シフトが重複する</td><td>同じスタッフの勤務日と時間帯を確認してください。</td></tr><tr><td>人件費が想定と違う</td><td>時給設定、休憩、実績打刻を確認してください。</td></tr></tbody></table>',12)])])}const f=a(d,[["render",l]]);export{p as __pageData,f as default};
